            // Parse XML content
            stringReader = new StringReader(xmlContent);
            Document document = saxBuilder.build(stringReader);

            // Get root element
            Element rootElement = document.getRootElement();

            // Find the <message> element
            Element messageElement = rootElement.getChild("message");

            // Return text content if <message> element exists
            if (messageElement != null) {
                return messageElement.getTextTrim();
            }

            return null;

        } catch (JDOMException e) {
            // Invalid XML format or parsing error
            return null;
        } catch (Exception e) {
            // Re-throw unexpected exceptions
            throw e;
        } finally {
            // Clean up resources
            if (stringReader != null) {
                stringReader.close();
            }
        }
    }
